const topics = $input.all().map(i => i.json);
const now = new Date();
const fourteenDaysAgo = new Date(now - 14 * 24 * 60 * 60 * 1000);

// Filter: not used in 14 days
const eligible = topics.filter(t => {
  if (!t.last_used_at) return true;
  return new Date(t.last_used_at) < fourteenDaysAgo;
});

// Weighted random selection
const totalWeight = eligible.reduce((s, t) => s + parseFloat(t.weight || 1), 0);
const selected = [];
const used = new Set();

while (selected.length < 3 && used.size < eligible.length) {
  let r = Math.random() * totalWeight;
  for (const topic of eligible) {
    if (used.has(topic.id)) continue;
    r -= parseFloat(topic.weight || 1);
    if (r <= 0) {
      selected.push(topic);
      used.add(topic.id);
      break;
    }
  }
}

return selected.map(t => ({ json: t }));

const response = $json;
const content = response.content?.[0]?.text || '';

// Parse sections
const hookMatch = content.match(/\[HOOK[^\]]*\](.+?)\n/s);
const problemMatch = content.match(/\[PROBLEM[^\]]*\](.+?)\[/s);
const reframeMatch = content.match(/\[REFRAME[^\]]*\](.+?)\[/s);
const tipMatch = content.match(/\[TIP[^\]]*\](.+?)\[/s);
const ctaMatch = content.match(/\[CTA[^\]]*\](.+?)$/ms);
const captionMatch = content.match(/Caption:(.+?)\n/i);
const hashtagMatch = content.match(/hashtag[s]?:(.+?)\n/i);
const thumbMatch = content.match(/Thumbnail[^:]*:(.+?)\n/i);

return [{
  json: {
    script: content,
    caption: (captionMatch?.[1] || '').trim(),
    hashtags: (hashtagMatch?.[1] || '#energy #sleep #focus #voltsleep #productivity').trim(),
    thumbnail_text: (thumbMatch?.[1] || '').trim(),
    hook_text: (hookMatch?.[1] || '').trim(),
  }
}];

const script = $json.script;
const lines = script.split('\n').filter(l => l.trim() && !l.startsWith('-') && !l.startsWith('Caption') && !l.startsWith('Hashtag') && !l.startsWith('Thumbnail'));

let srt = '';
let counter = 1;
let timeMs = 0;
const avgDuration = 3000; // 3s per line

for (const line of lines.slice(0, 10)) {
  const clean = line.replace(/\[.*?\]/g, '').trim();
  if (!clean || clean.length < 3) continue;

  const startSec = Math.floor(timeMs / 1000);
  const endSec = Math.floor((timeMs + avgDuration) / 1000);
  const startTime = formatSrtTime(timeMs);
  const endTime = formatSrtTime(timeMs + avgDuration);

  srt += `${counter}\n${startTime} --> ${endTime}\n${clean}\n\n`;
  counter++;
  timeMs += avgDuration;
}

function formatSrtTime(ms) {
  const h = Math.floor(ms / 3600000).toString().padStart(2, '0');
  const m = Math.floor((ms % 3600000) / 60000).toString().padStart(2, '0');
  const s = Math.floor((ms % 60000) / 1000).toString().padStart(2, '0');
  const msRem = (ms % 1000).toString().padStart(3, '0');
  return `${h}:${m}:${s},${msRem}`;
}

return [{ json: { ...$json, srt_subtitles: srt } }];

const post = $json;
const baseUrl = 'https://voltsleep.nl';
const day = new Date().toISOString().split('T')[0];

const platforms = ['tiktok', 'instagram', 'youtube', 'facebook'];
const times = ['09:00', '13:00', '19:00'];
const postIndex = $itemIndex + 1;
const scheduleTime = times[postIndex - 1] || '09:00';

const results = platforms.map(platform => {
  const utm = `${baseUrl}?utm_source=${platform}&utm_medium=organic&utm_campaign=daily_${day}&utm_content=hook_${postIndex}`;

  let caption = post.caption;
  // Platform-specific formatting
  if (platform === 'tiktok') {
    caption = `${post.caption}\n\n${post.hashtags}\n\nLink in bio`;
  } else if (platform === 'instagram') {
    caption = `${post.caption}\n\n${post.hashtags}\n\nLink in bio for free energy profile`;
  } else if (platform === 'youtube') {
    caption = `${post.caption} #shorts ${post.hashtags}`;
  } else if (platform === 'facebook') {
    caption = `${post.caption}\n\n${post.hashtags}`;
  }

  return {
    json: {
      platform,
      day_number: Math.ceil((new Date() - new Date('2026-03-01')) / (1000 * 60 * 60 * 24)) + 1,
      post_index: postIndex,
      script: post.script,
      caption,
      hashtags: post.hashtags,
      cta_variant: postIndex === 1 ? 'soft' : postIndex === 2 ? 'direct' : 'urgency',
      srt_subtitles: post.srt_subtitles,
      thumbnail_text: post.thumbnail_text,
      utm_link: utm,
      scheduled_at: `${day}T${scheduleTime}:00Z`,
      status: 'scheduled',
    }
  };
});

return results;
